	matches := packageRegex.FindStringSubmatch(protoDef)
	if len(matches) < 2 {
		return fmt.Errorf("invalid package declaration")
	}

	packageName := matches[1]
	validPackage := regexp.MustCompile(`^[a-zA-Z][a-zA-Z0-9_.]*$`)
	if !validPackage.MatchString(packageName) {
		return fmt.Errorf("invalid package name")
	}

	importRegex := regexp.MustCompile(`import\s+["']([^"']+)["']`)
	imports := importRegex.FindAllStringSubmatch(protoDef, -1)
	allowedImports := map[string]bool{
		"google/protobuf/any.proto":       true,
		"google/protobuf/timestamp.proto": true,
		"google/protobuf/duration.proto":  true,
		"google/protobuf/empty.proto":     true,
		"google/protobuf/struct.proto":    true,
	}

	for _, imp := range imports {
		if len(imp) > 1 {
			importPath := imp[1]
			if !allowedImports[importPath] {
				return fmt.Errorf("import not allowed: %s", importPath)
			}
		}
	}

	return nil
